=== nas-tools.ts: overcommit/sysctl/dirty defs + context ===
1183:    description: "Shows the I/O scheduler, queue depth limit, and read-ahead for each block device. Also runs iostat -x for per-device await/util% if available. Wrong scheduler (e.g. bfq on a RAID array) inflates I/O await and contributes to high iowait. Recommended: mq-deadline for HDDs/RAID; none or mq-deadline for SSDs. Use set_io_scheduler to change.",
2968:    name: "set_vm_overcommit_memory",
2969:    description: "WRITE — Sets vm.overcommit_memory via sysctl. Use value 1 to allow overcommit (fixes invoked/synologand OOM conditions). Change is live immediately but not persistent across reboots. Pass value (0, 1, or 2) in filter.",
2974:      if (!/^[012]$/.test(value)) throw new Error("set_vm_overcommit_memory: value must be 0, 1, or 2.");
2977:        `sysctl vm.overcommit_memory 2>&1`,
2980:        `sysctl -w vm.overcommit_memory=${value} 2>&1`,
2983:        `sysctl vm.overcommit_memory 2>&1`,
2989:    name: "persist_vm_overcommit_memory",
2990:    description: "WRITE — Persists the vm.overcommit_memory sysctl setting across reboots by writing to /etc/sysctl.conf on the NAS host. Run after set_vm_overcommit_memory to make the change survive a reboot. Pass value in filter (default: 1).",
2995:      if (!/^[012]$/.test(value)) throw new Error("persist_vm_overcommit_memory: value must be 0, 1, or 2.");
2997:        `echo '=== CURRENT vm.overcommit_memory ENTRIES IN sysctl.conf ==='`,
2998:        `grep -n 'vm.overcommit_memory' /host/etc/sysctl.conf 2>/dev/null || echo '(none found)'`,
3000:        `sed -i '/vm\\.overcommit_memory/d' /host/etc/sysctl.conf 2>&1`,
3001:        `echo "vm.overcommit_memory=${value}" >> /host/etc/sysctl.conf`,
3002:        `echo '=== VERIFY (sysctl.conf) ==='`,
3003:        `grep 'vm.overcommit_memory' /host/etc/sysctl.conf`,
3005:        `sysctl vm.overcommit_memory 2>&1`,
3011:    name: "set_io_scheduler",
3017:      if (!raw) throw new Error("set_io_scheduler: pass filter as 'device scheduler', e.g. 'sda mq-deadline'.");
3019:      if (parts.length !== 2) throw new Error("set_io_scheduler: filter must be exactly two words: device then scheduler.");
3021:      if (!/^[a-z0-9]+$/.test(device)) throw new Error("set_io_scheduler: invalid device name — use e.g. sda, md0, nvme0n1.");
3023:      if (!valid.includes(scheduler)) throw new Error(`set_io_scheduler: scheduler must be one of: ${valid.join(", ")}.`);
3040:    name: "set_vm_dirty_ratios",
3041:    description: "WRITE — Tunes vm.dirty_ratio and vm.dirty_background_ratio via sysctl. Lowering these forces dirty pages to flush more aggressively, smoothing out iowait spikes from large write bursts. Default Linux values: dirty_ratio=20 dirty_background_ratio=10. Recommended for NAS: 5 and 3. Pass as 'dirty_ratio=N dirty_background_ratio=M' in filter. Not persistent across reboots.",
3048:      if (!drMatch && !dbrMatch) throw new Error("set_vm_dirty_ratios: filter must contain dirty_ratio=N and/or dirty_background_ratio=M.");
3051:      if (dr !== null && (dr < 1 || dr > 80)) throw new Error("set_vm_dirty_ratios: dirty_ratio must be 1–80.");
3052:      if (dbr !== null && (dbr < 1 || dbr > 50)) throw new Error("set_vm_dirty_ratios: dirty_background_ratio must be 1–50.");
3053:      if (dr !== null && dbr !== null && dbr >= dr) throw new Error("set_vm_dirty_ratios: dirty_background_ratio must be less than dirty_ratio.");
3056:        `sysctl vm.dirty_ratio vm.dirty_background_ratio vm.dirty_expire_centisecs vm.dirty_writeback_centisecs 2>&1`,
3060:      if (dr !== null) cmds.push(`sysctl -w vm.dirty_ratio=${dr} 2>&1`);
3061:      if (dbr !== null) cmds.push(`sysctl -w vm.dirty_background_ratio=${dbr} 2>&1`);
3062:      cmds.push(`echo ''`, `echo '=== VERIFY ==='`, `sysctl vm.dirty_ratio vm.dirty_background_ratio 2>&1`, `echo 'Note: not persistent across reboots.'`);
3068:    name: "set_ionice",
3074:      if (!raw) throw new Error("set_ionice: pass filter as 'PID class [priority]', e.g. '1234 3' or '1234 2 6'.");
3079:      if (!pid || !/^\d+$/.test(pid)) throw new Error("set_ionice: first field must be a numeric PID.");
3080:      if (!cls || !["2", "3"].includes(cls)) throw new Error("set_ionice: class must be 2 (best-effort) or 3 (idle). Class 1 (realtime) is not permitted — it would give the process unconditional disk priority.");
3081:      if (prio !== undefined && !/^[0-7]$/.test(prio)) throw new Error("set_ionice: priority must be 0–7 (0=highest within class, 7=lowest).");
3781:  set_vm_overcommit_memory: "write_storage",
3782:  persist_vm_overcommit_memory: "write_storage",
3783:  set_io_scheduler: "write_storage",
3784:  set_vm_dirty_ratios: "write_storage",
3785:  set_ionice: "write_storage",
