1	// Package validator enforces tier rules and the hard-block list.
2	package validator
3	
4	import (
5		"errors"
6		"regexp"
7		"strings"
8	)
9	
10	// Tier constants mirror the three permission levels.
11	const (
12		TierRead    = 1 // read-only: auto-executes, no approval needed
13		TierService = 2 // service ops: restart packages/containers; approval required
14		TierFile    = 3 // file ops: touches user data volumes; approval required
15	)
16	
17	// driveRecursiveGrep matches a recursive grep/find against a Synology internal
18	// data store. Extracted to named vars so BlockExplanation can describe exactly
19	// this case without the pattern drifting from the hard-block below.
20	var (
21		driveRecursiveGrepA = regexp.MustCompile(`(?i)\bgrep\b.*-[a-zA-Z]*[rR][a-zA-Z]*\s.*(@synologydrive|@SynologyDriveShareSync|/var/packages/SynologyDrive)`)
22		driveRecursiveGrepB = regexp.MustCompile(`(?i)\bgrep\b.*(@synologydrive|@SynologyDriveShareSync|/var/packages/SynologyDrive).*-[a-zA-Z]*[rR]`)
23	)
24	
25	// hardBlocked is a list of patterns that are NEVER permitted regardless of tier.
26	// These could brick the NAS, destroy data, modify the OS, or lock out admins.
27	var hardBlocked = []*regexp.Regexp{
28		// Disk destruction
29		regexp.MustCompile(`(?i)\bmkfs\b`),
30		regexp.MustCompile(`(?i)\bfdisk\b`),
31		regexp.MustCompile(`(?i)\bparted\b`),
32		regexp.MustCompile(`(?i)\bmdadm\s+--fail\b`),
33		regexp.MustCompile(`(?i)\bdd\s+if=`),
34		regexp.MustCompile(`(?i)\bwipefs\b`),
35		// Root filesystem destruction
36		regexp.MustCompile(`(?i)\brm\s+(-\S*f\S*\s+)*/?$`),
37		regexp.MustCompile(`(?i)\brm\s+(-\S+\s+)*/boot\b`),
38		regexp.MustCompile(`(?i)\brm\s+(-\S+\s+)*/usr\b`),
39		regexp.MustCompile(`(?i)\brm\s+(-\S+\s+)*/etc\b`),
40		// System software — DSM/Synology binaries must not be modified
41		regexp.MustCompile(`(?i)(>|>>|tee)\s+/usr/syno`),
42		regexp.MustCompile(`(?i)\bsynopkg\s+(install|uninstall|remove)\b`),
43		// Firmware / kernel
44		regexp.MustCompile(`(?i)\bflash_eraseall\b`),
45		regexp.MustCompile(`(?i)\bnandwrite\b`),
46		regexp.MustCompile(`(?i)\binsmod\b`),
47		regexp.MustCompile(`(?i)\brmmod\b`),
48		// Ptrace code-injection vectors — blocked even though CAP_SYS_PTRACE is granted.
49		// strace (read-only syscall tracing) remains unblocked and tier-1 executable.
50		// gdb/lldb can call arbitrary functions in a traced process via "call system(...)".
51		regexp.MustCompile(`(?i)\bgdb\b`),
52		regexp.MustCompile(`(?i)\blldb\b`),
53		// Destructive hdparm operations — security erase, standby/sleep, write-cache toggle.
54		// Safe read flags (-I device identity, -t throughput test) remain unblocked.
55		regexp.MustCompile(`(?i)\bhdparm\b.*--security-`),
56		regexp.MustCompile(`(?i)\bhdparm\b.*\s-[yYW]\b`),
57		// dd writing directly to a device or /proc — would be a memory/disk write vector.
58		// dd if= is already blocked above; this adds the of= form.
59		regexp.MustCompile(`(?i)\bdd\b.*\bof=/dev/`),
60		regexp.MustCompile(`(?i)\bdd\b.*\bof=/proc/`),
61		// User account manipulation
62		regexp.MustCompile(`(?i)\buseradd\b`),
63		regexp.MustCompile(`(?i)\buserdel\b`),
64		regexp.MustCompile(`(?i)\busermod\b`),
65		regexp.MustCompile(`(?i)\bgroupadd\b`),
66		regexp.MustCompile(`(?i)\bgroupdel\b`),
67		regexp.MustCompile(`(?i)\bpasswd\s+\S`), // passwd <user> but not plain passwd
68		// NAS shutdown (use DSM UI for planned maintenance)
69		regexp.MustCompile(`(?i)\bshutdown\b`),
70		regexp.MustCompile(`(?i)\breboot\b`),
71		regexp.MustCompile(`(?i)\bpoweroff\b`),
72		regexp.MustCompile(`(?i)\bhalt\b`),
73		regexp.MustCompile(`(?i)\bsystemctl\s+(poweroff|halt|reboot)\b`),
74		// Package manager (apt/opkg/pip global installs)
75		regexp.MustCompile(`(?i)\bapt(-get)?\s+(install|remove|purge)\b`),
76		regexp.MustCompile(`(?i)\bopkg\s+(install|remove)\b`),
77		regexp.MustCompile(`(?i)\bpip\s+install\b`),
78		regexp.MustCompile(`(?i)\bnpm\s+install\s+-g\b`),
79		// Recursive grep/find on Synology internal data stores.
80		// These directories contain millions of opaque file objects; a recursive
81		// grep never returns useful results and will thrash disk I/O for days.
82		// Use targeted find -maxdepth or a database query instead.
83		driveRecursiveGrepA,
84		driveRecursiveGrepB,
85		// Mount destructive operations
86		regexp.MustCompile(`(?i)\bumount\s+/volume`),
87		regexp.MustCompile(`(?i)\bmount\s+.*--bind.*/volume`),
88		// Docker socket is effectively host-level control, so only a tiny allowlist
89		// of monitor-stack actions may use it. Everything else is blocked outright.
90		regexp.MustCompile(`(?i)\bdocker\s+(run|create|cp|plugin|network|volume|context|swarm|stack|builder|buildx)\b`),
91	}
92	
93	// safeRedirectRe strips redirect forms that are not writes:
94	// - N>/dev/null or >>/dev/null  (discard output)
95	// - N>&M                        (fd-to-fd, e.g. 2>&1)
96	var (
97		safeRedirectRe   = regexp.MustCompile(`\d*>>?\s*/dev/null|\d*>&\d*`)
98		outputRedirectRe = regexp.MustCompile(`>\s*\S`)
99		actualDockerRe   = regexp.MustCompile(`(?im)(^|[;&|(\$]\s*)(?:/(?:usr/)?(?:local/)?bin/)?docker(\s|$)`)
100		dockerInvokeRe   = regexp.MustCompile(`(?i)(?:/(?:usr/)?(?:local/)?bin/)?docker\b.*`)
101	)
102	
103	// hasRealOutputRedirect returns true only when the command redirects output
104	// to an actual file destination (not /dev/null, not fd-to-fd like 2>&1,
105	// and not comparison operators inside quoted awk/shell strings).
106	func hasRealOutputRedirect(command string) bool {
107		s := stripQuotedStrings(command)
108		s = safeRedirectRe.ReplaceAllString(s, "")
109		return outputRedirectRe.MatchString(s)
110	}
111	
112	func hasActualDockerCommand(command string) bool {
113		return actualDockerRe.MatchString(stripQuotedStrings(command))
114	}
115	
116	func dockerInvocations(command string) []string {
117		clean := stripQuotedStrings(command)
118		var invocations []string
119		for _, line := range strings.Split(clean, "\n") {
120			for _, part := range strings.FieldsFunc(line, func(r rune) bool {
121				return r == ';' || r == '&' || r == '|'
122			}) {
123				if match := dockerInvokeRe.FindString(strings.TrimSpace(part)); match != "" {
124					invocation := strings.TrimSpace(match)
125					invocation = strings.TrimPrefix(invocation, "/usr/local/bin/")
126					invocation = strings.TrimPrefix(invocation, "/usr/bin/")
127					invocations = append(invocations, invocation)
128				}
129			}
130		}
131		return invocations
132	}
133	
134	func dockerInvocationsAllowed(command string, allowed []*regexp.Regexp) bool {
135		invocations := dockerInvocations(command)
136		if len(invocations) == 0 {
137			return true
138		}
139		for _, invocation := range invocations {
140			if !matchesAny(invocation, allowed) {
141				return false
142			}
143		}
144		return true
145	}
146	
147	func stripQuotedStrings(command string) string {
148		var b strings.Builder
149		b.Grow(len(command))
150		inSingle := false
151		inDouble := false
152		escaped := false
153		for _, r := range command {
154			switch {
155			case escaped:
156				if !inSingle && !inDouble {
157					b.WriteRune(r)
158				}
159				escaped = false
160			case r == '\\' && inDouble:
161				escaped = true
162			case r == '\'' && !inDouble:
163				inSingle = !inSingle
164			case r == '"' && !inSingle:
165				inDouble = !inDouble
166			case inSingle || inDouble:
167				// Quoted text is data or labels, not shell structure.
168			default:
169				b.WriteRune(r)
170			}
171		}
172		return b.String()
173	}
174	
175	// writePatterns identifies commands that modify state (tier 2+).
176	// Used to prevent Tier 1 execution of write operations.
177	var writePatterns = []*regexp.Regexp{
178		regexp.MustCompile(`(?i)\b(rm|mv|cp|ln|mkdir|rmdir|touch|chmod|chown|chattr)\b`),
179		regexp.MustCompile(`(?im)(^|[;&|]\s*)tee\s+(-a\s+)?/(tmp|var|volume\d+|home|root|etc|usr|lib|opt|run|mnt|btrfs)/\S+`),
180		regexp.MustCompile(`(?i)\b(sed|awk)\s+(-i|--in-place)\b`), // in-place edit
181		regexp.MustCompile(`(?im)(^|[;&|]\s*)sync(\s|$)`),
182		regexp.MustCompile(`(?i)\bsysctl\s+-w\b`),
183		regexp.MustCompile(`(?i)\bionice\b.*-c`), // ionice -c sets I/O class; plain ionice -p (read) stays tier 1
184		regexp.MustCompile(`(?i)\bdd\b.*\bof=`),  // dd writing anywhere (device/proc covered by hard-block above)
185		regexp.MustCompile(`(?i)\b(systemctl|synopkg|synoservicectl)\s+(start|stop|restart|enable|disable)\b`),
186		regexp.MustCompile(`(?i)SYNO\.Docker\.Container.*method=(stop|start)`),
187		regexp.MustCompile(`(?im)(^|[;&|]\s*)docker\s+(start|stop|restart|rm)\b`),
188		regexp.MustCompile(`(?im)(^|[;&|]\s*)docker\s+compose\s+(restart|stop|up|pull|build)\b`),
189		regexp.MustCompile(`(?im)(^|[;&|]\s*)ssh-keygen\b`),
190		regexp.MustCompile(`(?im)(^|[;&|]\s*)kill\b`),
191		regexp.MustCompile(`(?im)(^|[;&|]\s*)pkill\b`),
192		regexp.MustCompile(`(?im)(^|[;&|]\s*)nohup\b`),
193		regexp.MustCompile(`(?im)(^|[;&|]\s*)at\b`),              // at-job scheduling
194		regexp.MustCompile(`(?im)(^|[;&|]\s*)crontab\s+-[er]\b`), // crontab edit/remove
195		// DSM WebAPI write operations (package stop/start, backup trigger, task run/enable/disable)
196		regexp.MustCompile(`(?i)SYNO\.(Core\.Package|Backup\.Task|Core\.TaskScheduler).*method=(stop|start|run|run_now|trigger|delete|enable|disable)`),
197	}
198	
199	// filePatterns identifies file-system write operations that touch user data.
200	// These require Tier 3 (approval + preview required).
201	var filePatterns = []*regexp.Regexp{
202		regexp.MustCompile(`(?i)\b(rm|mv|cp|ln|mkdir|rmdir|touch|chmod|chown|chattr)\b.*(/volume\d+/|/home/\w|/root/)`),
203		regexp.MustCompile(`(?i)\b(sed|awk)\s+(-i|--in-place)\b.*(/volume\d+/|/home/\w|/root/)`),
204		regexp.MustCompile(`(?i)\b(echo|printf|tee|cat)\b.*(>>?|\\|\\s*tee\\s+)(/volume\d+/|/home/\w|/root/)`),
205		regexp.MustCompile(`(>>?)\s*/volume`), // redirect into volume
206		regexp.MustCompile(`(>>?)\s*/home/\w`),
207		regexp.MustCompile(`(>>?)\s*/root/`),
208		regexp.MustCompile(`(?i)\brename\b.*\.old\b`),
209	}
210	
211	var (
212		allowedServiceCommands = []*regexp.Regexp{
213			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg restart SynologyDrive$`),
214			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg restart SynologyDriveShareSync$`),
215			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg restart HyperBackup$`),
216			regexp.MustCompile(`^/(?:host/)?usr/syno/bin/synopkg status [A-Za-z0-9._-]+(?: 2>&1)?(?: \|\| .+)?$`),
217			regexp.MustCompile(`^/usr/syno/bin/synowebapi --exec api=SYNO\.Docker\.Container version=1 method=(start|stop) name='"synology-monitor-agent"'$`),
218			regexp.MustCompile(`^/usr/syno/bin/synowebapi --exec api=SYNO\.Docker\.Container version=1 method=stop name='"synology-monitor-agent"' && sleep 3 && /usr/syno/bin/synowebapi --exec api=SYNO\.Docker\.Container version=1 method=start name='"synology-monitor-agent"'$`),
219		}
220	
221		allowedReadDockerCommands = []*regexp.Regexp{
222			regexp.MustCompile(`^(?:/usr/local/bin/)?docker ps(\s|$)`),
223			regexp.MustCompile(`^docker stats --no-stream`),
224			regexp.MustCompile(`^docker inspect`),
225			regexp.MustCompile(`^docker logs\b`),
226			regexp.MustCompile(`^docker port\b`),
227			regexp.MustCompile(`^docker diff\b`),
228			regexp.MustCompile(`^docker top\b`),
229			regexp.MustCompile(`(?s)^for dir in /sys/fs/cgroup/blkio/docker/\*/; do.+docker inspect`),
230		}
231	)
232	
233	// Validate checks a command against tier rules.
234	// It returns an error if the command is hard-blocked or if it
235	// requires a higher tier than what was requested.
236	func Validate(command string, requestedTier int) error {
237		if disallowedDockerCompose(command) {
238			return errors.New("docker compose command is not in the allowlist")
239		}
240	
241		// 1. Hard-block check — always fails regardless of tier
242		for _, re := range hardBlocked {
243			if re.MatchString(command) {
244				return errors.New("command is hard-blocked: " + re.String())
245			}
246		}
247	
248		if hasActualDockerCommand(command) {
249			if requestedTier == TierRead {
250				if !dockerInvocationsAllowed(command, allowedReadDockerCommands) {
251					return errors.New("docker read command is not in the allowlist")
252				}
253			} else if requestedTier >= TierService {
254				if !matchesAny(command, allowedServiceCommands) && !dockerInvocationsAllowed(command, allowedServiceCommands) {
255					return errors.New("service command is not in the allowlist")
256				}
257			}
258		}
259		if strings.Contains(command, "SYNO.Docker.Container") && matchesAny(command, []*regexp.Regexp{
260			regexp.MustCompile(`(?i)method=(start|stop)`),
261		}) && !matchesAny(command, allowedServiceCommands) {
262			return errors.New("DSM container service command is not in the allowlist")
263		}
264	
265		// 2. Tier 1: must be read-only
266		if requestedTier == TierRead {
267			for _, re := range writePatterns {
268				if re.MatchString(command) {
269					return errors.New("command requires tier 2 or higher (detected write pattern)")
270				}
271			}
272			if hasRealOutputRedirect(command) {
273				return errors.New("command requires tier 2 or higher (detected write pattern)")
274			}
275		}
276	
277		// 3. Tier 2: may be a service op but must not touch user files
278		if requestedTier == TierService {
279			if strings.Contains(command, "/volume1/") && !strings.Contains(command, "/volume1/docker/synology-monitor-agent") {
280				return errors.New("tier 2 commands may not touch user data paths")
281			}
282			for _, re := range filePatterns {
283				if re.MatchString(command) {
284					return errors.New("command touches user data and requires tier 3")
285				}
286			}
287		}
288	
289		return nil
290	}
291	
292	// ClassifyTier returns the minimum tier required for a command.
293	// The caller (web app issue agent) uses this to decide whether to
294	// auto-execute (tier 1) or prompt for approval (tier 2/3).
295	func ClassifyTier(command string) int {
296		if disallowedDockerCompose(command) {
297			return -1
298		}
299		for _, re := range hardBlocked {
300			if re.MatchString(command) {
301				return -1 // never
302			}
303		}
304		isWrite := false
305		for _, re := range writePatterns {
306			if re.MatchString(command) {
307				isWrite = true
308				break
309			}
310		}
311		if !isWrite {
312			isWrite = hasRealOutputRedirect(command)
313		}
314		if !isWrite {
315			return TierRead
316		}
317		for _, re := range filePatterns {
318			if re.MatchString(command) {
319				return TierFile
320			}
321		}
322		return TierService
323	}
324	
325	// IsHardBlocked returns true if the command can never be executed.
326	func IsHardBlocked(command string) bool {
327		if disallowedDockerCompose(command) {
328			return true
329		}
330		for _, re := range hardBlocked {
331			if re.MatchString(command) {
332				return true
333			}
334		}
335		return false
336	}
337	
338	// BlockExplanation returns a client-facing reason a command is hard-blocked.
339	// Unlike Summary (which echoes the command), it states WHY, that the block is
340	// permanent and stateless, and what to do instead. This is the only signal an
341	// MCP session receives on a refusal — without it, sessions misread the block as
342	// a "rate limit" or "session degradation" and give up. Returns "" if the command
343	// is not hard-blocked.
344	func BlockExplanation(command string) string {
345		if !IsHardBlocked(command) {
346			return ""
347		}
348		// This guard is stateless and pure: the same command is refused identically on
349		// every call. It is not a per-session quota and not a degradation symptom.
350		const footer = " This block is permanent and stateless — it is NOT a rate limit, quota, or session-degradation symptom, and it fired on the command pattern alone. Retrying it or starting a fresh session will return the exact same result; change the command instead."
351	
352		switch {
353		case driveRecursiveGrepA.MatchString(command), driveRecursiveGrepB.MatchString(command):
354			return "Recursive grep against a Synology internal data store (@synologydrive / @SynologyDriveShareSync / the SynologyDrive package dir) is blocked: these hold millions of opaque objects and one such grep ran 4d11h on production before it was caught. Do this instead: grep a specific named log file non-recursively (e.g. @synologydrive/log/*.log or syncfolder.log), or query the monitoring database for historical data." + footer
355		case matchesAny(command, []*regexp.Regexp{
356			regexp.MustCompile(`(?i)\b(mkfs|fdisk|parted|wipefs|flash_eraseall|nandwrite)\b`),
357			regexp.MustCompile(`(?i)\bdd\b.*\b(if=|of=/dev/|of=/proc/)`),
358			regexp.MustCompile(`(?i)\bmdadm\s+--fail\b`),
359			regexp.MustCompile(`(?i)\bhdparm\b`),
360		}):
361			return "This is a destructive disk/firmware operation that could brick the NAS or destroy an array, so it is blocked at every tier. There is no safe way to run it through this interface — use the DSM UI for planned maintenance." + footer
362		case matchesAny(command, []*regexp.Regexp{
363			regexp.MustCompile(`(?i)\b(shutdown|reboot|poweroff|halt)\b`),
364			regexp.MustCompile(`(?i)\bsystemctl\s+(poweroff|halt|reboot)\b`),
365		}):
366			return "Powering off or rebooting the NAS is blocked here — do planned maintenance from the DSM UI so the shutdown is graceful." + footer
367		case matchesAny(command, []*regexp.Regexp{
368			regexp.MustCompile(`(?i)\b(useradd|userdel|usermod|groupadd|groupdel)\b`),
369			regexp.MustCompile(`(?i)\bpasswd\s+\S`),
370		}):
371			return "User/group account changes are blocked to avoid locking out admins — manage accounts in DSM Control Panel." + footer
372		case matchesAny(command, []*regexp.Regexp{
373			regexp.MustCompile(`(?i)\b(apt(-get)?|opkg)\s+(install|remove|purge)\b`),
374			regexp.MustCompile(`(?i)\bpip\s+install\b`),
375			regexp.MustCompile(`(?i)\bnpm\s+install\s+-g\b`),
376			regexp.MustCompile(`(?i)\bsynopkg\s+(install|uninstall|remove)\b`),
377		}):
378			return "Installing or removing packages on the host is blocked — it would mutate the NAS OS outside the monitored deploy path." + footer
379		case matchesAny(command, []*regexp.Regexp{
380			regexp.MustCompile(`(?i)\bdocker\s+(run|create|cp|plugin|network|volume|context|swarm|stack|builder|buildx)\b`),
381		}):
382			return "This docker subcommand grants host-level control and is outside the small monitor-stack allowlist, so it is blocked. Use DSM Container Manager WebAPI for container lifecycle operations." + footer
383		default:
384			return "This command matches a permanent safety rule (it could destroy data, modify the OS/firmware, manage accounts, or take the NAS offline)." + footer
385		}
386	}
387	
388	// Summary returns a human-readable description of what a command does,
389	// used for building the approval preview shown to the operator.
390	func Summary(command string) string {
391		cmd := strings.TrimSpace(command)
392		if strings.HasPrefix(cmd, "cat ") {
393			return "Read file: " + strings.TrimPrefix(cmd, "cat ")
394		}
395		if strings.Contains(cmd, "synopkg restart") {
396			return "Restart Synology package"
397		}
398		if strings.Contains(cmd, "SYNO.Docker.Container") && strings.Contains(cmd, "method=stop") && strings.Contains(cmd, "method=start") {
399			return "Restart DSM-managed container"
400		}
401		if strings.Contains(cmd, "SYNO.Docker.Container") && strings.Contains(cmd, "method=stop") {
402			return "Stop DSM-managed container"
403		}
404		if strings.Contains(cmd, "SYNO.Docker.Container") && strings.Contains(cmd, "method=start") {
405			return "Start DSM-managed container"
406		}
407		if strings.Contains(cmd, "docker") && strings.Contains(cmd, "restart") {
408			return "Restart Docker container"
409		}
410		if strings.Contains(cmd, "mv ") && strings.Contains(cmd, ".old") {
411			return "Rename file to .old (quarantine)"
412		}
413		return cmd
414	}
415	
416	func matchesAny(command string, patterns []*regexp.Regexp) bool {
417		for _, re := range patterns {
418			if re.MatchString(command) {
419				return true
420			}
421		}
422		return false
423	}
424	
425	func disallowedDockerCompose(command string) bool {
426		return strings.Contains(strings.TrimSpace(command), "docker compose")
427	}
